#include <stdio.h>
#include <stdlib.h>

// Node structure
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Function to create a new node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to sort the linked list
Node* sortLL(Node* head) {
    // Base case: if the list is empty or contains only one node
    if (head == NULL || head->next == NULL) {
        return head;
    }

    // Split the list into two halves
    Node* slow = head;
    Node* fast = head->next;
    while (fast != NULL && fast->next != NULL) {
        slow = slow->next;
        fast = fast->next->next;
    }

    // Split the list into two halves
    Node* second = slow->next;
    slow->next = NULL;

    // Recursively sort the two halves
    head = sortLL(head);
    second = sortLL(second);

    // Merge the two sorted halves
    return merge(head, second);
}

// Function to merge two sorted linked lists
Node* merge(Node* first, Node* second) {
    Node* dummy = createNode(0);
    Node* current = dummy;
    while (first != NULL && second != NULL) {
        if (first->data < second->data) {
            current->next = first;
            first = first->next;
        } else {
            current->next = second;
            second = second->next;
        }
        current = current->next;
    }

    // If there are remaining nodes in either list, append them to the result
    if (first != NULL) {
        current->next = first;
    } else if (second != NULL) {
        current->next = second;
    }

    Node* sortedList = dummy->next;
    free(dummy);
    return sortedList;
}

// Function to print the linked list
void printLinkedList(Node* head) {
    while (head != NULL) {
        printf("%d ", head->data);
        head = head->next;
    }
    printf("\n");
}

int main() {
    // Create a sample linked list: 3 -> 2 -> 5 -> 4 -> 1
    Node* head = createNode(3);
    head->next = createNode(2);
    head->next->next = createNode(5);
    head->next->next->next = createNode(4);
    head->next->next->next->next = createNode(1);

    printf("Original Linked List: ");
    printLinkedList(head);

    head = sortLL(head);

    printf("Sorted Linked List: ");
    printLinkedList(head);

    return 0;
}

